using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: Default discriminator property renamed from
        // "Discriminator" to "$type" in EF Core 9. Preserve the old name
        // so existing documents remain readable.
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonProperty("Discriminator");

        // Breaking change #2: Default id format changed from
        // "{Discriminator}|{Key}" to just the key. Preserve the old format
        // so existing documents (e.g. "Blog|1") are still found.
        modelBuilder.Entity<Blog>().HasIdProperty(b => b.Id)
            .HasIdJsonProperty("id");

        // Breaking change #3: HasIndex() now throws on the Cosmos provider
        // instead of being silently ignored. Removed.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

